(function () {
    cc.SicboGroupItem = cc.Class({
        "extends": cc.Component,
        properties: {
            avatar: cc.Avatar,
            lbNickName: cc.Label,
            lbBalance: cc.Label,
        },
        updateItem: function (item, itemID) {
            let accountInfo = item.Account;
            var avatarID = accountInfo.Avatar;
            if (avatarID <= 0) {
                avatarID = 1;
            }

            this.avatar.setAvatar(cc.AccountController.getInstance().getAvatarImage(avatarID));
            this.lbNickName.string = accountInfo.NickName;
            this.lbBalance.string = '$' + cc.Tool.getInstance().formatNumberK(accountInfo.Balance);
            this.item = item;
            this.itemID = itemID;
        },
    });
}).call(this);
